import numpy as np

def update_edge_distance(edge_distance, local_opt_tour, edge_n_used):
    updated_edge_distance = np.copy(edge_distance)

    for i in range(len(edge_distance)):
        for j in range(len(edge_distance)):
            if edge_n_used[i, j] == 0 and i != j:
                ratio_i = np.sum(edge_n_used[i] == 0) / len(edge_distance)
                ratio_j = np.sum(edge_n_used[j] == 0) / len(edge_distance)
                updated_edge_distance[i, j] += ratio_i
                updated_edge_distance[j, i] += ratio_j

    return updated_edge_distance
